import React, { Component } from "react";
const tinycolor = require("tinycolor2");

export default class GridItem extends Component {
  onMouseOver = () => {
    this.props.hoverToPaletteBoxItem(this.props.i.color);
  };

  clickOnItem = () => {
    chrome.runtime.sendMessage({
      action: "clickCopyFromPalletbox",
      color: `#${tinycolor(this.props.i.color).toHex8()}`,
    });

    this.props.getTextToFooter("Copy");
  };
  render() {
    const { i } = this.props;
    let itemClass;

    if (tinycolor(this.props.i.color).toHex8().includes("ffffff")) {
      itemClass = "PaletteBoxGrid_Item Border";
    } else {
      itemClass = "PaletteBoxGrid_Item";
    }

    return (
      <li
        className={itemClass}
        onMouseOver={this.onMouseOver}
        onClick={this.clickOnItem}
      >
        <div
          className="PaletteBox_Item_Left"
          style={{
            backgroundColor: `rgba(${i.color.r}, ${i.color.g}, ${i.color.b})`,
          }}
        ></div>
        <div className="PaletteBox_Item_Right">
          <div
            style={{
              backgroundColor: `rgba(${i.color.r}, ${i.color.g}, ${i.color.b},${i.color.a})`,
            }}
          ></div>
        </div>
      </li>
    );
  }
}
