import React, { Component } from "react";
import "./ColorPicker.css";

export default class ColorPicker extends Component {
  activeEDropper = () => {
    chrome.runtime.sendMessage(
      {
        action: "pikerStart",
      },
      () => {
        window.close();
      }
    );
  };

  render() {
    return (
      <div style={{ width: "100%", height: "100%" }}>
        {this.props.sorryBanner === true ? (
          <div className="SorryBanner">
            <div className="SorryBanner_Img"></div>
            <p className="SorryBanner_Text">
              Whoops.<br></br>Can't pick<br></br>from this page
            </p>
          </div>
        ) : (
          <div className="ColorPicker" onClick={this.activeEDropper}>
            <div className="ColorPicker_Img"></div>
            <p className="ColorPicker_Text">
              Click to pick<br></br>color from web
            </p>
          </div>
        )}
      </div>
    );
  }
}
