import React, { useState } from "react";
import { CustomPicker } from "react-color";

const tinycolor = require("tinycolor2");
var {
  Hue,
  Saturation,
  Alpha,
  EditableInput,
} = require("react-color/lib/components/common");

export default function CusCol(props) {
  const [color, setColor] = useState(props.color);

  return (
    <div
      style={{
        position: "absolute",
        width: "100%",
        height: "100%",
        margin: 0,
        padding: 0,
      }}
    >
      <ColorPickerWrapped
        color={color}
        setColor={setColor}
        getCurrentColor={props.getCurrentColor}
        getSelectColor={props.getSelectColor}
      />
    </div>
  );
}

class ColorPicker extends React.Component {
  handleChange = (data) => {
    this.props.setColor(data);

    const color = tinycolor(data);
    const item = {
      hex: `#${color.toHex8()}`,
      hsl: color.toHsl(),
      rgb: color.toRgb(),
    };
    this.props.getCurrentColor(item);
  };

  sendSelectColor = () => {
    const color = tinycolor(this.props.hsv);
    const item = {
      hex: `#${color.toHex8()}`,
      hsl: color.toHsl(),
      rgb: color.toRgb(),
    };

    this.props.getSelectColor(item);
  };

  render() {
    return (
      <div style={{ float: "left", width: "128px" }}>
        <div
          style={{
            float: "left",
            width: "128px",
            height: "100px",
            position: "relative",
            marginBottom: "8px",
          }}
        >
          <Saturation
            {...this.props}
            onChange={this.handleChange}
            pointer={SatPicker}
          />
        </div>
        <div
          style={{
            float: "left",
            width: "128px",
            height: "14px",
            position: "relative",
            marginBottom: "8px",
          }}
        >
          <Hue {...this.props} onChange={this.handleChange} pointer={Picker} />
        </div>
        <div
          style={{
            float: "left",
            width: "128px",
            height: "14px",
            position: "relative",
          }}
        >
          <Alpha
            {...this.props}
            pointer={Picker}
            onChange={this.handleChange}
          />
        </div>
        <div className="ColorPicker_InputBox">
          <button
            className="ColorPicker_InputBox_Btn"
            onClick={this.sendSelectColor}
          >
            Select
          </button>
          <EditableInput
            style={{
              wrap: {
                width: 66,
                height: 25,
                background: "rgba(224, 225, 231, 0.2)",
                borderRadius: "8px",
              },
              input: {
                fontStyle: "normal",
                color: "#4b4a50",
                position: "absolute",
                top: 3,
                background: "transparent",
                width: "100%",
                border: 0,
                fontWeight: "bold",
                fontSize: "14px",
                lineHeight: "22px",
              },
            }}
            value={this.props.hex}
            onChange={this.handleChange}
          />
        </div>
      </div>
    );
  }
}

const ColorPickerWrapped = CustomPicker(ColorPicker);

function Picker() {
  return (
    <div
      style={{
        width: 9,
        height: 14,
        backgroundSize: "contain",
        backgroundRepeat: "no-repeat",
        backgroundPosition: "bottom",
        boxSizing: "border-box",
        transform: "translate(-50%)",
        backgroundImage: `url("data:image/svg+xml,%3C%3Fxml version='1.0' encoding='UTF-8'%3F%3E%3Csvg xmlns='http://www.w3.org/2000/svg' width='270' height='240'%3E%3Cpath transform='rotate(179.87457275390625 135,114.5)' d='M5,5H265L135,230'/%3E%3C/svg%3E")`,
      }}
    />
  );
}

function SatPicker() {
  return (
    <div
      style={{
        width: 10,
        height: 10,
        borderRadius: 10,
        background: "rgba(255,255,255,0.2)",
        border: "1px solid white",
        boxSizing: "border-box",
      }}
    />
  );
}
