import React, { Component } from "react";
import "./App.css";
import $ from "jquery";
import Header from "./components/Header/Header";
import Main from "./components/Main/Main";
import Footer from "./components/Footer/Footer";

export default class App extends Component {
  state = {
    activeBtn: "eyedropper",
    sorryBanner: false,
    footerText: "Hover over squares to preview..",
    config: null,
    options: null,
  };

  componentDidMount() {
    const _this = this;
    window.chrome.tabs.query(
      { active: true, currentWindow: true },
      function (tabs) {
        if (tabs[0].url.includes("chrome://")) {
          _this.setState({
            sorryBanner: true,
          });
        }
      }
    );

    window.chrome.storage.sync.get((d) => {
      if (d.hasOwnProperty("configFromColorPicker")) {
        this.setState({
          config: d.configFromColorPicker.colors,
        });
      }
    });

    window.chrome.storage.sync.get((d) => {
      if (d.hasOwnProperty("optionsFromColorPicker")) {
        this.setState({
          options: d.optionsFromColorPicker.options,
        });
      }
    });
  }

  getActiveBtn = (btn) => {
    this.setState({
      activeBtn: btn,
    });
  };

  getTextToFooter = (e) => {
    if (e.type === "mouseenter") {
      this.setState({
        footerText: "Click the square to select and copy to clipboard.",
      });
    } else if (e.type === "mouseleave") {
      this.setState({
        footerText: "Hover over squares to preview..",
      });
    } else if (e === "Copy") {
      this.setState({
        footerText: "Copied to clipboard!",
      });

      setTimeout(() => {
        this.setState({
          footerText: "Hover over squares to preview..",
        });
      }, 1500);
    }
  };

  render() {
    $(document).ready(function () {
      const imgBox = $(".ColorPicker_InputBox")[0]
        ? $(".ColorPicker_InputBox")[0].previousSibling.childNodes[0]
            .childNodes[0].childNodes[0]
        : null;

      if (imgBox !== null) {
        imgBox.style.borderRadius = "6px";
      }

      const gradBox = $(".ColorPicker_InputBox")[0]
        ? $(".ColorPicker_InputBox")[0].previousSibling.childNodes[0]
            .childNodes[1]
        : null;

      if (gradBox !== null) {
        gradBox.style.borderRadius = "6px";
      }
    });
    const { activeBtn, footerText, sorryBanner, config, options } = this.state;

    return (
      <div className="App">
        <Header getActiveBtn={this.getActiveBtn} activeBtn={activeBtn} />
        {config !== null ? (
          <Main
            activeBtn={activeBtn}
            getTextToFooter={this.getTextToFooter}
            sorryBanner={sorryBanner}
            config={config}
            options={options}
          />
        ) : null}

        <Footer text={footerText} />
      </div>
    );
  }
}
