import React, { Component } from "react";
import "./MainColums.css";

import ColorPicker from "./ColorPicker/ColorPicker";
import PaletteEditor from "./PaletteEditor/PaletteEditor";

export default class MainColums extends Component {
  cliclOnValue = (e) => {
    if (e.target.className === "Box_Value_hash") {
      if (this.props.options.pickBehaviour.copyHash === false) {
        navigator.clipboard.writeText(e.target.textContent);
      } else {
        navigator.clipboard.writeText(e.target.textContent.slice(1));
      }
    } else {
      navigator.clipboard.writeText(e.target.textContent);
    }

    this.props.getTextToFooter("Copy");
  };

  render() {
    const {
      newColor,
      pickedColor,
      sorryBanner,
      getCurrentColor,
      getSelectColor,
    } = this.props;

    let hexToHeader;

    if (newColor.rgb.a === 1) {
      hexToHeader = newColor.hex.slice(0, -2);
    } else {
      hexToHeader = newColor.hex;
    }

    let hexToH;

    if (pickedColor.rgb.a === 1) {
      hexToH = pickedColor.hex.slice(0, -2);
    } else {
      hexToH = pickedColor.hex;
    }

    let boxClassNew;
    if (newColor.hex.includes("ffffff")) {
      boxClassNew = "MCR_ValueBox BorderNew";
    } else {
      boxClassNew = "MCR_ValueBox";
    }

    let boxClassPick;
    if (pickedColor.hex.includes("ffffff")) {
      boxClassPick = "MCR_ValueBox BorderPick";
    } else {
      boxClassPick = "MCR_ValueBox";
    }

    return (
      <div className="MainColums">
        <div className="MainColums_Left">
          {this.props.activeBtn === "eyedropper" ? (
            <ColorPicker sorryBanner={sorryBanner} />
          ) : (
            <PaletteEditor
              getCurrentColor={getCurrentColor}
              color={newColor.hex}
              getSelectColor={getSelectColor}
            />
          )}
        </div>

        <div className="MainColums_Right">
          <div className="MainColums_Right_NewBox">
            <div className="MCR_Box_Text">
              <p>New:</p>
              <span>{hexToHeader}</span>
            </div>
            <div
              className={boxClassNew}
              style={{
                backgroundColor: newColor.hex,
              }}
            >
              <div className="Box_Value_hash" onClick={this.cliclOnValue}>
                {hexToHeader}
              </div>
              <div className="Box_Value_hsl" onClick={this.cliclOnValue}>
                hsl ({Math.round(newColor.hsl.h)}, {Math.round(newColor.hsl.s)},
                {Math.round(newColor.hsl.l)})
              </div>
              <div className="Box_Value_rgb" onClick={this.cliclOnValue}>
                rgba ({newColor.rgb.r}, {newColor.rgb.g}, {newColor.rgb.b},{" "}
                {newColor.rgb.a})
              </div>
            </div>
          </div>
          <div className="MainColums_Right_PickedBox">
            <div className="MCR_Box_Text">
              <p>Picked:</p>
              <span>{hexToH}</span>
            </div>
            <div
              className={boxClassPick}
              style={{
                backgroundColor: pickedColor.hex,
              }}
            >
              <div className="Box_Value_hash" onClick={this.cliclOnValue}>
                {hexToH}
              </div>
              <div className="Box_Value_hsl" onClick={this.cliclOnValue}>
                hsl ({Math.round(pickedColor.hsl.h)},
                {Math.round(pickedColor.hsl.s)},{Math.round(pickedColor.hsl.l)})
              </div>
              <div className="Box_Value_rgb" onClick={this.cliclOnValue}>
                rgba ({pickedColor.rgb.r}, {pickedColor.rgb.g},
                {pickedColor.rgb.b}, {pickedColor.rgb.a})
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }
}
