import React, { Component } from "react";

export default class Form extends Component {
  state = {
    query: "",
  };

  changeQuery = (e) => {
    this.setState({ query: e.currentTarget.value });
  };

  cancel = () => {
    this.setState({ query: "" });
    this.props.cancelAddColection();
  };

  save = (e) => {
    e.preventDefault();

    function isBlank(str) {
      return !str || /^\s*$/.test(str);
    }

    if (isBlank(this.state.query)) {
      this.setState({
        query: "",
      });
      return;
    } else {
      this.setState({
        query: "",
      });
      this.props.onSubmit(this.state.query);
    }
  };

  render() {
    return (
      <form onSubmit={this.save} className="PaletteBox_Header_Form">
        <input
          type="text"
          autoFocus
          maxLength="20"
          value={this.state.query}
          className="PaletteBox_Input"
          onChange={this.changeQuery}
        />
        <span className="PaletteBox_Input_Cross" onClick={this.cancel}></span>
        <div
          className="PaletteBox_Select_Save iconsHP"
          onClick={this.save}
        ></div>
      </form>
    );
  }
}
