import React from "react";
import "./PaletteEditor.css";

import CusCol from "./CusCol";

export default function PaletteEditor({
  getCurrentColor,
  color,
  getSelectColor,
}) {
  return (
    <div className="PaletteEditor">
      <CusCol
        getCurrentColor={getCurrentColor}
        color={color}
        getSelectColor={getSelectColor}
      />
    </div>
  );
}
