import * as React from "react";
import { Select } from "@mui/material";

import MenuItem from "@mui/material/MenuItem";

export default function BasicSelect({ selectList, onChange }) {
  let value = selectList.filter((i) => i.active === true);

  const handleChange = (event) => {
    let itemId = selectList.filter((i) => i.value === event.target.value);
    onChange(itemId);
  };

  return (
    <Select
      sx={{
        height: 25,
        fontSize: 14,
        backgroundColor: "#f9f9fa",
      }}
      defaultValue={value[0].value}
      value={value[0].value}
      onChange={handleChange}
    >
      {selectList.map((i) => (
        <MenuItem value={i.value}>{i.value}</MenuItem>
      ))}
    </Select>
  );
}
