import React, { Component } from "react";
import { CSVLink } from "react-csv";
import "./PaletteBox.css";

import PaletteBoxGrid from "./PaletteBoxGrid/PaletteBoxGrid";
import BasicSelect from "./Select";
import Form from "./Form";
const tinycolor = require("tinycolor2");

export default class PaletteBox extends Component {
  state = {
    inputAddColection: false,
  };

  addPaletteToColections = () => {
    this.setState({
      inputAddColection: true,
    });
  };

  cancelAddPaletteToColections = () => {
    this.setState({
      inputAddColection: false,
    });
  };

  savePaletteToColections = (q) => {
    this.setState({
      inputAddColection: false,
    });

    this.props.addSelectList(q);
  };

  onChangeSelect = (item) => {
    this.props.getCurrentSelectList(item);
  };

  deletePalette = () => {
    const item = this.props.selectList.filter((i) => i.active === true);
    this.props.clearList(item[0].id);
  };

  downloadData = (arr) => {
    const res = arr.map((i) => {
      const color = tinycolor(i.color);
      const h = color.toHsl();
      const r = color.toRgb();

      const item = {
        Hex: `#${color.toHex8()}`,
        HSL: `hsl(${Math.round(h.h)}, ${Math.round(h.s)}, ${Math.round(h.l)})`,
        RGB: `rgb(${Math.round(r.r)}, ${Math.round(r.g)}, ${Math.round(
          r.b
        )}, ${Math.round(r.a)})`,
      };
      return item;
    });

    return res;
  };

  render() {
    const { inputAddColection } = this.state;
    const { selectList, hoverToPaletteBoxItem, getTextToFooter } = this.props;
    let viewColors = selectList.filter((i) => i.active === true);
    const colorData = this.downloadData(viewColors[0].colors);

    return (
      <div className="PaletteBox">
        <div className="PaletteBox_Header">
          <div className="PaletteBox_Header_BoxText">
            {inputAddColection === false ? (
              <div className="PaletteBox_Header_Select_Box">
                <BasicSelect
                  onChange={this.onChangeSelect}
                  selectList={selectList}
                />
                <div
                  className="PaletteBox_Select_Plus iconsHP"
                  onClick={this.addPaletteToColections}
                ></div>
              </div>
            ) : (
              <Form
                cancelAddColection={this.cancelAddPaletteToColections}
                onSubmit={this.savePaletteToColections}
              />
            )}
          </div>

          <div className="PaletteBox_Header_Btns">
            <div
              className="PaletteBox_Header_Btns_Delete iconsHP"
              onClick={this.deletePalette}
            ></div>
            <CSVLink
              data={colorData}
              filename="ColorPickerPalette.csv"
              className="PaletteBox_Header_Btns_Dwn iconsHP"
            ></CSVLink>
          </div>
        </div>
        <PaletteBoxGrid
          colorsList={viewColors[0].colors}
          hoverToPaletteBoxItem={hoverToPaletteBoxItem}
          getTextToFooter={getTextToFooter}
        />
      </div>
    );
  }
}
