import React, { Component } from "react";
import "./Header.css";

export default class Header extends Component {
  clickOnBtn = (e) => {
    this.props.getActiveBtn(e.currentTarget.attributes[1].value);
  };

  render() {
    const { activeBtn } = this.props;

    return (
      <div className="Header">
        <div
          className={
            activeBtn === "eyedropper"
              ? "Header_Button active-btn"
              : "Header_Button"
          }
          lable="eyedropper"
          onClick={this.clickOnBtn}
        >
          <div
            className={
              activeBtn === "eyedropper"
                ? "Header_Button_Img EyeDropper-active"
                : "Header_Button_Img EyeDropper"
            }
          ></div>
        </div>
        <div
          className={
            activeBtn === "palette"
              ? "Header_Button active-btn"
              : "Header_Button"
          }
          lable="palette"
          onClick={this.clickOnBtn}
        >
          <div
            className={
              activeBtn === "palette"
                ? "Header_Button_Img Palette-active"
                : "Header_Button_Img Palette"
            }
          ></div>
        </div>
      </div>
    );
  }
}
