import React, { Component } from "react";
import "./Main.css";

import MainColums from "./MainColums/MainColums";
import PaletteBox from "./PaletteBox/PaletteBox";
const tinycolor = require("tinycolor2");
const shortid = require("shortid");

export default class Main extends Component {
  state = {
    newColor: this.props.config.newColor,
    pickedColor: this.props.config.pickedColor,
    selectList: this.props.config.selectList,
  };

  componentDidMount() {
    const _this = this;
    window.chrome.runtime.sendMessage(
      {
        action: "getPickedColor",
      },
      (value) => {
        if (value !== "") {
          const color = tinycolor(value);
          _this.setLastColor(color.toRgb());
          const item = {
            hex: `#${color.toHex8()}`,
            hsl: color.toHsl(),
            rgb: color.toRgb(),
          };
          _this.setState({
            newColor: item,
            pickedColor: item,
          });
        }
      }
    );
  }

  setCurrentColor = (data) => {
    this.setState({
      newColor: {
        hex: data.hex,
        hsl: data.hsl,
        rgb: data.rgb,
      },
    });
  };

  setSelectColor = (data) => {
    this.setState({
      pickedColor: {
        hex: data.hex,
        hsl: data.hsl,
        rgb: data.rgb,
      },
    });

    window.chrome.runtime.sendMessage({
      action: "colorToIconBox",
      color: data,
    });

    this.setLastColor(data.rgb);
  };

  setLastColor = (data) => {
    const hexData = tinycolor(data);
    const item = this.state.selectList.filter((i) => i.active === true);
    const cl = item[0].colors;

    const listHex = cl.map((i) => {
      const a = tinycolor(i.color);
      return a.toHex8();
    });

    if (listHex.includes(hexData.toHex8())) {
      return;
    } else {
      if (cl.length <= 53) {
        cl.unshift({ color: data });
      } else {
        return;
      }
    }

    this.setNewConfigToStorage();
  };

  deletePaletteColection = (id) => {
    const list = this.state.selectList;

    if (id === "1") {
      const newList = list.map((i) => {
        if (i.id === id) {
          i.colors = [];
        }

        return i;
      });

      this.setState({
        selectList: newList,
      });

      this.setNewConfigToStorage();
    } else {
      const newList = list.filter((i) => {
        if (i.id !== id) {
          return i;
        }
      });

      const res = newList.map((i, index) => {
        if (index === 0) {
          i.active = true;
        }

        return i;
      });
      this.setState({
        selectList: res,
      });

      this.setNewConfigToStorage();
    }
  };

  hoverToPaletteBoxItem = (value) => {
    if (
      value.r === 251 &&
      value.g === 249 &&
      value.b === 249 &&
      value.a === 1
    ) {
      return;
    } else {
      const color = tinycolor(value);
      const item = {
        hex: `#${color.toHex8()}`,
        hsl: color.toHsl(),
        rgb: color.toRgb(),
      };
      this.setState({
        newColor: item,
      });
    }
  };

  applyCurrentPalette = (data) => {
    const list = this.state.selectList.map((i) => {
      if (i.id === data[0].id) {
        i.active = true;
      } else {
        i.active = false;
      }
      return i;
    });
    this.setState({
      selectList: list,
    });
  };

  addSelectList = (query) => {
    const item = {
      id: shortid.generate(),
      value: query,
      active: true,
      colors: [],
    };

    const newList = this.state.selectList.map((i) => {
      if (i.active === true) {
        i.active = false;
      }
      return i;
    });
    newList.push(item);
    this.setState({
      selectList: newList,
    });

    this.setNewConfigToStorage();
  };

  setNewConfigToStorage = () => {
    window.chrome.storage.sync.get((d) => {
      if (d.hasOwnProperty("configFromColorPicker")) {
        const item = {
          colors: this.state,
          options: d.configFromColorPicker.options,
        };

        window.chrome.storage.sync.set({
          configFromColorPicker: item,
        });
      }
    });
  };

  render() {
    const { newColor, pickedColor, selectList } = this.state;
    const { activeBtn, sorryBanner, getTextToFooter, options } = this.props;

    return (
      <div className="Main">
        <MainColums
          activeBtn={activeBtn}
          getCurrentColor={this.setCurrentColor}
          getSelectColor={this.setSelectColor}
          sorryBanner={sorryBanner}
          newColor={newColor}
          pickedColor={pickedColor}
          getTextToFooter={getTextToFooter}
          options={options}
        />
        <PaletteBox
          addSelectList={this.addSelectList}
          getCurrentSelectList={this.applyCurrentPalette}
          selectList={selectList}
          clearList={this.deletePaletteColection}
          hoverToPaletteBoxItem={this.hoverToPaletteBoxItem}
          getTextToFooter={getTextToFooter}
        />
      </div>
    );
  }
}
